import { useState } from "react";

export default function CheckoutForm({ cart }) {
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      const res = await fetch("/api/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ items: cart }),
      });
      if (!res.ok) {
        const body = await res.json();
        throw new Error(body.error);   // ← bug: leaks server error as-is to user; no 5xx vs 4xx distinction
      }
      setSuccess(true);
    } catch (err) {
      setError(err.message);   // ← raw server error shown to user: 'Internal server error'
    }
  }

  if (success) return <p>Order placed!</p>;
  return (
    <form onSubmit={handleSubmit}>
      <button type="submit">Place Order (${cart.total})</button>
      {error && <p className="error">{error}</p>}
    </form>
  );
}

